from typing import Any


def build_answers(ctx: dict[str, Any]) -> dict[str, str]:
    return {'publication_status': f"Publication status is **{ctx['publication']}**: {ctx['contract_failures']} contract failures and {ctx['quality_failures']} coded quality failures. Passing code checks still requires approved metric meaning and source completeness.", 'source_of_truth': f"The project treats source ownership as event-specific rather than choosing one universal system. The lineage table contains {len(ctx['data_lineage'])} source-to-decision mappings; referral receipt, scheduling, assessment completion and capacity each retain separate source ownership.", 'reconciliation': 'The current synthetic build has no blocking source reconciliation failure. In production I would reconcile at record grain, explain refresh cut-off, time-zone, status and inclusion-rule differences, and leave no unexplained residual before publishing.', 'wait_definition': f"End-to-end patient-experience wait is {ctx['_fmt'](ctx['wait_patient']['median_days'])} days median versus {ctx['_fmt'](ctx['wait_accepted']['median_days'])} days from acceptance. The acceptance-based measure is {ctx['_fmt'](abs(ctx['wait_accepted']['median_difference_vs_patient_experience']))} days shorter because it excludes referral-processing time.", 'right_censoring': 'Recent referral cohorts should not be compared on eventual completion without maturity controls. This project uses 30/60/90-day cohort outcomes and labels period comparisons as potentially right-censored.', 'freshness': f"True extract freshness cannot be proven from event timestamps alone. The event-coverage table shows {ctx['stale_source']['table']} with {ctx['_fmt'](ctx['stale_source']['coverage_lag_vs_referral_cutoff_days'])} days lag versus the referral cutoff, but production needs extraction timestamps and source SLAs.", 'missingness': f"{ctx['nonnullable_missing_answer']} {ctx['nullable_example']} Nullable pathway timestamps should be interpreted by business state, not automatically imputed.", 'period_change': f"The largest relative period shift is {ctx['largest_period']['metric'].replace('_', ' ')}: {ctx['_fmt'](ctx['largest_period']['previous_value'])} to {ctx['_fmt'](ctx['largest_period']['recent_value'])} ({ctx['_pct'](ctx['largest_period']['relative_change'])}). Referrals changed {ctx['_pct'](ctx['referrals_change'])}, capacity {ctx['_pct'](ctx['capacity_change'])}, and contact time {ctx['_pct'](ctx['contact_change'])}."}
